const require_validation = require('./validation.cjs');
const require_findAyahIdBySurah = require('./findAyahIdBySurah.cjs');
const require_findRubAlHizbByAyahId = require('./findRubAlHizbByAyahId.cjs');

//#region src/findRubAlHizb.ts
/**
* Finds the Juz (part) and Rub-ul-Hizb/Maqra (quarter section) of the Quran that the given Ayah (verse) belongs to.
*
* @param surah - The Surah (chapter) number.
* @param ayah - The Ayah (verse) number. Defaults to 1 if not provided.
* @param data - The Lists object containing SurahList and HizbQuarterList.
* @returns An object containing the Juz (part) number, Hizb (section) number, and the index of the Hizb that the given Ayah belongs to.
*/
function findRubAlHizb(surah, ayah = 1, data) {
	require_validation.checkValidSurah(surah, data.meta);
	return require_findRubAlHizbByAyahId.findRubAlHizbByAyahId(require_findAyahIdBySurah.findAyahIdBySurah(surah, ayah, data), data);
}

//#endregion
exports.findRubAlHizb = findRubAlHizb;